@import "tailwindcss";

/* ============================================================
   MB Partners — Design Tokens
   ============================================================ */
:root {
  --blue:     #4733E6;
  --blue-dk:  #3826C4;
  --blue-bg:  #EDEBFC;
  --blue-bg2: #F7F6FE;
  --txt:      #0E0E14;
  --muted:    #9A9CA8;
  --muted2:   #6E707D;
  --line:     #ECECF1;
  --bg:       #FFFFFF;
  --bg2:      #F6F6F8;
  --green:    #1E9E6A;
  --green-bg: #E7F6EF;
  --amber:    #C07A12;
  --amber-bg: #FBF1DF;
  --red:      #D34545;
  --red-bg:   #FBE9E9;

  /* Motion timing */
  --ease-out: cubic-bezier(.2,.8,.2,1);
  --ease-spring: cubic-bezier(.34,1.56,.64,1);
}

/* Extend Tailwind with MBP tokens */
@theme inline {
  --color-blue:      #4733E6;
  --color-blue-dk:   #3826C4;
  --color-blue-bg:   #EDEBFC;
  --color-blue-bg2:  #F7F6FE;
  --color-mbp-txt:   #0E0E14;
  --color-muted:     #9A9CA8;
  --color-muted2:    #6E707D;
  --color-line:      #ECECF1;
  --color-bg2:       #F6F6F8;
  --color-green:     #1E9E6A;
  --color-green-bg:  #E7F6EF;
  --color-amber:     #C07A12;
  --color-amber-bg:  #FBF1DF;
  --color-mbp-red:   #D34545;
  --color-red-bg:    #FBE9E9;
}

/* ============================================================
   Base
   ============================================================ */
*  { box-sizing: border-box; -webkit-tap-highlight-color: transparent; }

body {
  font-family: 'Zen Kaku Gothic New', 'Inter', sans-serif;
  background: var(--bg2);
  color: var(--txt);
  font-size: 16px;
}

/* ============================================================
   Custom Scrollbars
   ============================================================ */
::-webkit-scrollbar          { width: 5px; height: 5px; }
::-webkit-scrollbar-track    { background: transparent; }
::-webkit-scrollbar-thumb    { background: var(--line); border-radius: 99px; }
::-webkit-scrollbar-thumb:hover { background: #CCCDD8; }

/* Firefox */
* { scrollbar-width: thin; scrollbar-color: var(--line) transparent; }

/* ============================================================
   Typography helpers
   ============================================================ */
.en {
  font-family: 'Inter', sans-serif;
  letter-spacing: .18em;
  text-transform: uppercase;
}

/* Tabular numbers for amounts */
.tnum { font-feature-settings: 'tnum'; }

/* ============================================================
   Buttons
   ============================================================ */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 7px;
  padding: 13px 22px;
  border-radius: 8px;
  font-family: inherit;
  font-size: .85rem;
  font-weight: 700;
  border: none;
  cursor: pointer;
  transition: background .18s, box-shadow .18s, opacity .18s, transform .14s var(--ease-spring);
}
.btn:disabled { opacity: .55; cursor: not-allowed; }
.btn:active:not(:disabled) { transform: scale(.96); }

.btn-p {
  background: var(--blue);
  color: #fff;
}
.btn-p:hover:not(:disabled) {
  background: var(--blue-dk);
  box-shadow: 0 6px 18px rgba(71,51,230,.3);
}

.btn-g {
  background: #fff;
  color: var(--txt);
  border: 1px solid var(--line);
}
.btn-g:hover:not(:disabled) {
  border-color: var(--blue);
  color: var(--blue);
}

/* ============================================================
   Form fields
   ============================================================ */
.fld {
  display: flex;
  flex-direction: column;
  gap: 6px;
  margin-bottom: 12px;
}
.fld label {
  font-size: .68rem;
  font-weight: 700;
  color: var(--muted2);
}
.fld input, .fld select, .fld textarea {
  border: 1.5px solid var(--line);
  border-radius: 8px;
  padding: 11px 13px;
  font-family: inherit;
  font-size: .9rem;
  color: var(--txt);
  background: #fff;
  transition: border-color .15s, box-shadow .15s;
  width: 100%;
}
.fld input::placeholder, .fld textarea::placeholder { color: var(--muted); }
.fld input:focus, .fld select:focus, .fld textarea:focus {
  outline: none;
  box-shadow: 0 0 0 3px var(--blue-bg);
  border-color: var(--blue);
}

/* ============================================================
   Eyebrow label
   ============================================================ */
.eyebrow {
  font-family: 'Inter', sans-serif;
  font-size: .55rem;
  font-weight: 600;
  letter-spacing: .28em;
  color: var(--blue);
  text-transform: uppercase;
}

/* ============================================================
   Card hover lift
   ============================================================ */
.card-hover {
  transition: box-shadow .2s var(--ease-out), transform .2s var(--ease-out);
}
.card-hover:hover {
  box-shadow: 0 8px 24px rgba(14,14,20,.1);
  transform: translateY(-2px);
}

/* Link row hover — left accent border */
.row-hover {
  transition: box-shadow .15s;
}
.row-hover:hover { box-shadow: inset 3px 0 0 var(--blue) !important; }

/* ============================================================
   Page transition
   ============================================================ */
.page-anim {
  animation: pageIn .28s var(--ease-out) both;
}

/* ============================================================
   Stagger list — first 8 children animate in sequence */
.stagger > * {
  animation: pageIn .32s var(--ease-out) both;
}
.stagger > *:nth-child(1) { animation-delay: 0ms; }
.stagger > *:nth-child(2) { animation-delay: 50ms; }
.stagger > *:nth-child(3) { animation-delay: 95ms; }
.stagger > *:nth-child(4) { animation-delay: 135ms; }
.stagger > *:nth-child(5) { animation-delay: 170ms; }
.stagger > *:nth-child(6) { animation-delay: 200ms; }
.stagger > *:nth-child(7) { animation-delay: 226ms; }
.stagger > *:nth-child(8) { animation-delay: 248ms; }

/* ============================================================
   Toast
   ============================================================ */
.toast {
  position: fixed;
  bottom: 32px;
  left: 50%;
  transform: translateX(-50%) translateY(0);
  background: var(--txt);
  color: #fff;
  padding: 12px 22px;
  border-radius: 10px;
  font-size: .74rem;
  font-weight: 600;
  z-index: 999;
  white-space: nowrap;
  box-shadow: 0 8px 24px rgba(14,14,20,.22);
  animation: toastIn .22s var(--ease-spring) both;
  pointer-events: none;
}
.toast.toast-success { background: var(--green); }
.toast.toast-error   { background: var(--red); }

/* ============================================================
   Status dot pulse
   ============================================================ */
.status-dot {
  display: inline-block;
  width: 8px; height: 8px;
  border-radius: 50%;
  flex-shrink: 0;
}
.status-dot.active {
  background: var(--green);
  animation: pulseDot 2.8s ease-in-out infinite;
}
.status-dot.pending { background: var(--amber); }
.status-dot.muted   { background: var(--muted); }

/* ============================================================
   Nav item active fill (console sidebar)
   ============================================================ */
.nav-link {
  transition: color .18s, background .18s, padding-left .18s;
}
.nav-link:hover:not(.nav-active) {
  background: var(--bg2) !important;
  color: var(--txt) !important;
}
.nav-link.nav-active {
  background: var(--blue-bg2);
  color: var(--blue);
  font-weight: 700;
}

/* Partner app bottom nav item */
.app-nav-item {
  transition: color .18s, transform .14s var(--ease-spring);
}
.app-nav-item:active { transform: scale(.88); }

/* ============================================================
   Skeleton / sheen loading
   ============================================================ */
.skeleton {
  background: linear-gradient(90deg, var(--line) 25%, #F0F0F4 50%, var(--line) 75%);
  background-size: 200% 100%;
  animation: skeletonWave 1.4s ease-in-out infinite;
  border-radius: 6px;
}

/* ============================================================
   Drawer slide-in
   ============================================================ */
.drawer-slide {
  animation: drawerIn .24s var(--ease-out) both;
}
.modal-fade {
  animation: modalBgIn .18s ease both;
}

/* ============================================================
   Animations
   ============================================================ */
@keyframes up {
  from { opacity: 0; transform: translateY(8px); }
  to   { opacity: 1; transform: translateY(0); }
}
@keyframes spin {
  to { transform: rotate(360deg); }
}
@keyframes drift {
  from { transform: translate(0,0) scale(1); }
  to   { transform: translate(-12px,12px) scale(1.04); }
}
@keyframes pulseDot {
  0%, 100% { opacity: 1; }
  50% { opacity: .45; }
}
@keyframes viewIn {
  from { opacity: 0; transform: translateY(8px); }
  to   { opacity: 1; transform: none; }
}
@keyframes pageIn {
  from { opacity: 0; transform: translateY(10px); }
  to   { opacity: 1; transform: none; }
}
@keyframes toastIn {
  from { opacity: 0; transform: translateX(-50%) translateY(14px); }
  to   { opacity: 1; transform: translateX(-50%) translateY(0); }
}
@keyframes drawerIn {
  from { transform: translateX(100%); }
  to   { transform: translateX(0); }
}
@keyframes modalBgIn {
  from { opacity: 0; }
  to   { opacity: 1; }
}
@keyframes sheen {
  to { transform: translateX(130%); }
}
@keyframes skeletonWave {
  0%   { background-position: 200% 0; }
  100% { background-position: -200% 0; }
}
@keyframes pulseScale {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.08); }
}
@keyframes fadeUp {
  from { opacity: 0; transform: translateY(16px); }
  to   { opacity: 1; transform: none; }
}

/* ============================================================
   Status rail dot pulse
   ============================================================ */
@keyframes stnPulse {
  0%, 100% { box-shadow: 0 0 0 4px var(--blue-bg); }
  50%       { box-shadow: 0 0 0 8px rgba(71,51,230,.12); }
}
.stnPulse {
  animation: stnPulse 2s ease-in-out infinite;
}

/* ============================================================
   SVG stroke-draw animation (circle circumference = 2π×45 ≈ 283)
   ============================================================ */
@keyframes draw {
  from { stroke-dashoffset: 283; }
  to   { stroke-dashoffset: 0; }
}
.draw {
  stroke-dasharray: 283;
  animation: draw .7s var(--ease-out) both;
}

/* ============================================================
   Kanban column drag-over highlight
   ============================================================ */
.col.over {
  background: var(--blue-bg2) !important;
  outline: 2px dashed rgba(71,51,230,.4);
  outline-offset: -2px;
}

/* ============================================================
   Drawer cascade stagger
   ============================================================ */
.cascade > * {
  animation: pageIn .28s var(--ease-out) both;
}
.cascade > *:nth-child(1) { animation-delay:   0ms; }
.cascade > *:nth-child(2) { animation-delay:  40ms; }
.cascade > *:nth-child(3) { animation-delay:  75ms; }
.cascade > *:nth-child(4) { animation-delay: 105ms; }
.cascade > *:nth-child(5) { animation-delay: 130ms; }
.cascade > *:nth-child(6) { animation-delay: 150ms; }
.cascade > *:nth-child(7) { animation-delay: 168ms; }
.cascade > *:nth-child(8) { animation-delay: 184ms; }

/* ============================================================
   Accordion smooth expand/collapse
   ============================================================ */
.accordion-body {
  overflow: hidden;
  max-height: 0;
  opacity: 0;
  transition: max-height .32s var(--ease-out), opacity .25s ease;
}
.accordion-body.open {
  max-height: 960px;
  opacity: 1;
}

/* ============================================================
   Design Language — Batch B (shared, reusable across all pages)
   Lightweight transform/opacity only · reduced-motion handled globally below
   ============================================================ */

/* Subtle interactive lift for rows / links (lighter than .card-hover) */
.lift { transition: background .16s var(--ease-out), box-shadow .16s var(--ease-out), transform .16s var(--ease-out); }
.lift:hover { background: var(--blue-bg2); transform: translateY(-1px); }

/* System-color chips: 紹介=青 / 協力=濃色 / 直販=中立 */
.chip {
  display: inline-flex; align-items: center; gap: 4px;
  font-size: .56rem; font-weight: 700; letter-spacing: .02em;
  padding: 2px 8px; border-radius: 20px; white-space: nowrap;
}
.chip-referral    { background: var(--blue-bg);  color: var(--blue); }
.chip-cooperation { background: #E7E4F7;          color: var(--blue-dk); }
.chip-direct      { background: var(--bg2);        color: var(--muted2); }

/* Timeline / feed dot */
.feed-dot { width: 8px; height: 8px; border-radius: 50%; flex-shrink: 0; }

/* Hero shine sweep — one-time gloss on mount */
.shine { position: relative; overflow: hidden; }
.shine::after {
  content: ''; position: absolute; top: 0; left: -60%; width: 50%; height: 100%;
  background: linear-gradient(100deg, transparent, rgba(255,255,255,.28), transparent);
  transform: skewX(-18deg);
  animation: shineSweep 1.5s var(--ease-out) .35s both;
}
@keyframes shineSweep { from { left: -60%; } to { left: 130%; } }

/* Vertical bar grow-in (transform-origin bottom) */
.bar-grow { transform-origin: bottom; animation: barGrow .6s var(--ease-out) both; }
@keyframes barGrow { from { transform: scaleY(0); } to { transform: scaleY(1); } }

/* Status-change highlight flash (foundation for later batches) */
.flash-highlight { animation: flashHighlight 1.1s var(--ease-out) both; }
@keyframes flashHighlight {
  0%   { background: var(--blue-bg); }
  100% { background: transparent; }
}

/* Gentle celebration pop for "嬉しい瞬間" (controlled, non-loud) */
.celebrate-pop { animation: celebratePop .5s var(--ease-spring) both; }
@keyframes celebratePop {
  0%   { transform: scale(.92); opacity: 0; }
  60%  { transform: scale(1.04); }
  100% { transform: scale(1); opacity: 1; }
}

/* Print styles for statement */
@media print {
  body * { visibility: hidden; }
  #docArea, #docArea * { visibility: visible; }
  #docArea { position: absolute; left: 0; top: 0; width: 100%; }
}

@media (prefers-reduced-motion: reduce) {
  *, *::before, *::after {
    animation-duration: .01ms !important;
    transition-duration: .01ms !important;
  }
}

