      <div style={{ display: 'flex', background: 'var(--bg2)', borderRadius: 10, padding: 4, margin: '0 20px 16px' }}>
        {[['all', 'すべて'], ['active', '進行中'], ['done', '完了']].map(([val, lbl]) => (
