                    padding: '14px 15px 13px', marginBottom: 10,
                  }}
                >
                  {/* Line 1 — 誰を/どの企業を + channel chip (left), 報酬 (right, concise) */}
                  <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                    <div style={{ display: 'flex', alignItems: 'center', gap: 8, flex: 1, minWidth: 0 }}>
